{{(() => {
	const type = ReportTypeSelect.selectedOptionValue;
	switch(type) {
		case 'all_orders': 
			const delivered = AllOrdersReport.data?.filter(o => o.status_display?.includes('Delivered') || o.payment_status?.includes('Already Paid')).length || 0;
			return delivered;
		case 'daily_cash_flow': 
			const totalRev = DailyCashFlowReport.data?.reduce((sum, row) => sum + (row.total_revenue || 0), 0) || 0;
			return `$${totalRev.toFixed(0)}`;
		case 'payment_analysis': 
			const analysisRev = PaymentAnalysisReport.data?.reduce((sum, row) => sum + (row.total_revenue || 0), 0) || 0;
			return `$${analysisRev.toFixed(0)}`;
		case 'monthly_summary': 
			const monthlyRev = MonthlyFinancialSummary.data?.reduce((sum, row) => sum + (row.total_revenue || 0), 0) || 0;
			return `$${monthlyRev.toFixed(0)}`;
		case 'business_metrics': 
			const metricsRev = BusinessMetricsDashboard.data?.[0]?.total_revenue || 0;
			return `$${metricsRev.toFixed(0)}`;
		default: 
			return "$0";
	}
})()}}
